mapper.update:
UPDATE tutor_appointment
start_time = #{startTime}, duration_minutes = #{durationMinutes}, status = #{status}, created_by = #{createdBy}, proposed_start_time = #{proposedStartTime}, proposed_by = #{proposedBy}, cancel_by = #{cancelBy}, remark = #{remark}, update_time = CURRENT_TIMESTAMP
WHERE id = #{id}

mapper.select:
SELECT
    id, parent_id, tutor_id, parent_job_posting_id, tutor_job_posting_id, subject_id, class_mode, city, address,
    start_time, duration_minutes, status, created_by, proposed_start_time, proposed_by, cancel_by, remark, create_time, update_time
FROM tutor_appointment
WHERE (parent_id = #{uid} OR tutor_id = #{uid})

    AND status = #{status}


    AND id < #{cursor}

ORDER BY id DESC
LIMIT #{pageSize}
